#ifndef RALLY_UTILS_DUMP_CATCHER_SYMBOLIZE_H
#define RALLY_UTILS_DUMP_CATCHER_SYMBOLIZE_H

#include <errno.h>
#include "rally/utils/dump_catcher/utilities.h"

#ifdef DUMP_CATCHER_OPEN

#include <link.h>  // For ElfW() macro.
// If there is no ElfW macro, let's define it by ourself.
#ifndef ElfW
# if SIZEOF_VOID_P == 4
#  define ElfW(type) Elf32_##type
# elif SIZEOF_VOID_P == 8
#  define ElfW(type) Elf64_##type
# else
#  error "Unknown sizeof(void *)"
# endif
#endif

namespace rally {
namespace log {

// Restrictions on the callbacks that follow:
//  - The callbacks must not use heaps but only use stacks.
//  - The callbacks must be async-signal-safe.

// Installs a callback function, which will be called right before a symbol name
// is printed. The callback is intended to be used for showing a file name and a
// line number preceding a symbol name.
// "fd" is a file descriptor of the object file containing the program
// counter "pc". The callback function should write output to "out"
// and return the size of the output written. On error, the callback
// function should return -1.
typedef int (*SymbolizeCallback)(int fd,
                                 void *pc,
                                 char *out,
                                 size_t out_size,
                                 uint64_t relocation);

void InstallSymbolizeCallback(SymbolizeCallback callback);

// Installs a callback function, which will be called instead of
// OpenObjectFileContainingPcAndGetStartAddress.  The callback is expected
// to searches for the object file (from /proc/self/maps) that contains
// the specified pc.  If found, sets |start_address| to the start address
// of where this object file is mapped in memory, sets the module base
// address into |base_address|, copies the object file name into
// |out_file_name|, and attempts to open the object file.  If the object
// file is opened successfully, returns the file descriptor.  Otherwise,
// returns -1.  |out_file_name_size| is the size of the file name buffer
// (including the null-terminator).
typedef int (*SymbolizeOpenObjectFileCallback)(uint64_t pc,
                                               uint64_t &start_address,
                                               uint64_t &base_address,
                                               char *out_file_name,
                                               int out_file_name_size);

void InstallSymbolizeOpenObjectFileCallback(
SymbolizeOpenObjectFileCallback callback);


// Symbolizes a program counter.  On success, returns true and write the
// symbol name to "out".  The symbol name is demangled if possible
// (supports symbols generated by GCC 3.x or newer).  Otherwise,
// returns false.
bool Symbolize(void *pc, char *out, int out_size);

}  // namespace log
}  // namespace rally

#endif //RALLY_UTILS_DUMP_CATCHER_SYMBOLIZE_H

#endif  // RALLY_DUMP_CATCHER_SYMBOLIZE_H
